import{M as e,O as t,h as n,m as r,p as i,s as a,u as o}from"./chunks/runtime-core.esm-bundler.DGewWfie.js";import{t as s}from"./chunks/plugin-vue_export-helper.BDNMzG2s.js";var c=JSON.parse(`{"title":"履歷摘要","description":"吳彥東（wuc656）的精簡履歷，整理現職、技術能力、代表經驗與合作方向。","frontmatter":{"title":"履歷摘要","description":"吳彥東（wuc656）的精簡履歷，整理現職、技術能力、代表經驗與合作方向。","outline":[2,3]},"headers":[],"relativePath":"resume.md","filePath":"resume.md","lastUpdated":1781683122000}`),l={name:`resume.md`},u={id:`履歷摘要`,tabindex:`-1`};function d(s,c,l,d,f,p){let m=e(`Badge`);return t(),o(`div`,null,[a(`h1`,u,[c[0]||=r(`履歷摘要 `,-1),n(m,{type:`tip`,text:`Resume`}),c[1]||=r(),c[2]||=a(`a`,{class:`header-anchor`,href:`#履歷摘要`,"aria-label":`Permalink to “履歷摘要”`},`​`,-1)]),c[3]||=i(`<div class="lead-panel"><h2>吳彥東（Yen-Tung Wu）</h2><p>全端軟體工程師，目前在 CMIS 中程資訊顧問有限公司負責 ERP Web 化，主力技術為 Go、Vue 與 Delphi 既有系統維護。</p></div><nav class="table-of-contents"><ul><li><a href="#核心資訊">核心資訊</a></li><li><a href="#工作經驗">工作經驗</a></li><li><a href="#技術摘要">技術摘要</a></li><li><a href="#代表經驗">代表經驗</a></li><li><a href="#可合作方向">可合作方向</a></li></ul></nav><div class="tip custom-block"><p class="custom-block-title">快速版本</p><p>如果你只想快速了解我，可以先看這一頁；更完整的個人背景、技術細節與作品紀錄分別放在「關於我」、「技術能力」與「專案作品」。</p></div><h2 id="核心資訊" tabindex="-1">核心資訊 <a class="header-anchor" href="#核心資訊" aria-label="Permalink to “核心資訊”">​</a></h2><div class="metric-grid"><div class="metric"><strong>現職</strong><span>軟體工程師 @ CMIS 中程資訊顧問有限公司</span></div><div class="metric"><strong>主力方向</strong><span>Delphi ERP 系統 Web 化，後端 Go + 前端 Vue</span></div><div class="metric"><strong>長期專案</strong><span>東東的創世神伺服器，自 2013 年起營運</span></div><div class="metric"><strong>聯絡</strong><span><a href="mailto:wuc656@gmail.com">wuc656@gmail.com</a> / <a href="https://github.com/wuc656">GitHub</a></span></div></div><h2 id="工作經驗" tabindex="-1">工作經驗 <a class="header-anchor" href="#工作經驗" aria-label="Permalink to “工作經驗”">​</a></h2><div class="timeline"><div class="timeline-item"><h3>2024/03/18 - 至今：CMIS 中程資訊顧問有限公司</h3><p>負責將 Delphi 2009 營建工程管理 ERP 逐步改寫為現代 Web 架構，並維護既有 Delphi 桌面系統。</p></div><div class="timeline-item"><h3>2023/09/19 - 2023/12/31：軍事訓練役</h3><p>完成 4 個月軍事訓練役，培養紀律、協作與抗壓能力。</p></div><div class="timeline-item"><h3>2019 - 2023：國立高雄科技大學 資訊工程系</h3><p>完成資訊工程訓練，累積資料結構、資料庫、網路與軟體工程基礎。</p></div></div><h2 id="技術摘要" tabindex="-1">技術摘要 <a class="header-anchor" href="#技術摘要" aria-label="Permalink to “技術摘要”">​</a></h2><table tabindex="0"><thead><tr><th>領域</th><th>技術</th><th>使用情境</th></tr></thead><tbody><tr><td>後端</td><td>Go、Echo、XORM</td><td>ERP Web API、資料存取、系統重構</td></tr><tr><td>前端</td><td>Vue、Vite、PrimeVue、TailwindCSS、MasterCSS</td><td>Web UI、後台系統、互動介面</td></tr><tr><td>桌面</td><td>Delphi 2009 / Object Pascal</td><td>既有桌面系統維護與功能擴充</td></tr><tr><td>運維</td><td>Windows、網路設定、伺服器架設</td><td>Minecraft 伺服器、個人服務與系統維護</td></tr><tr><td>開源</td><td>NPM package、GitHub Pages</td><td>個人專案、網站與套件維護</td></tr></tbody></table><h2 id="代表經驗" tabindex="-1">代表經驗 <a class="header-anchor" href="#代表經驗" aria-label="Permalink to “代表經驗”">​</a></h2><ul><li><strong>ERP 現代化</strong>：理解既有 Delphi 系統，再逐步轉換為 Go + Vue 的 Web 應用。</li><li><strong>跨技術維護</strong>：同時處理舊桌面系統與新 Web 技術棧，重視可漸進交付的改寫方式。</li><li><strong>社群營運</strong>：長期維護 Minecraft 伺服器，處理玩家支援、規則、內容、網站與 Discord 社群。</li><li><strong>內容與作品管理</strong>：整理個人網站、YouTube、Android 小作品與 NPM 套件資料。</li></ul><h2 id="可合作方向" tabindex="-1">可合作方向 <a class="header-anchor" href="#可合作方向" aria-label="Permalink to “可合作方向”">​</a></h2><div class="info custom-block"><p class="custom-block-title">合作主題</p><p>我適合參與需要理解既有系統、逐步重構、前後端整合、內部工具開發或社群型服務維護的工作。</p></div><ul><li>Go / Echo / XORM 後端 API</li><li>Vue / Vite / PrimeVue 前端介面</li><li>Delphi 2009 既有系統維護</li><li>ERP Web 化與系統重構</li><li>Minecraft 伺服器、Discord 社群與工具開發</li></ul><details class="details custom-block"><summary>延伸閱讀</summary><ul><li><a href="/about">關於我</a></li><li><a href="/skills">技術能力</a></li><li><a href="/projects">專案作品</a></li><li><a href="/career">職涯歷程</a></li><li><a href="/links">聯絡方式</a></li></ul></details>`,15)])}var f=s(l,[[`render`,d]]);export{c as __pageData,f as default};